                                bool IsOutput) {
  if (!I || !I->getParent() || !I->getFunction())
    return Operand;

  // Handle vector constants.
  if (auto *VTy = dyn_cast<VectorType>(Operand->getType())) {
    // Check if the vector is a splat of a scalar constant.
    if (Constant *Splat = Operand->getSplatValue()) {
      Constant *FlushedSplat = FlushFPConstant(Splat, I, IsOutput);
      if (!FlushedSplat)
        return nullptr;
      if (FlushedSplat == Splat)
        return Operand;
      return ConstantVector::getSplat(VTy->getElementCount(), FlushedSplat);
    }

    // Non-splat vector: process each element.
    Type *EltTy = VTy->getElementType();
    unsigned NumElts = VTy->getElementCount().getKnownMinValue();
    SmallVector<Constant*, 8> Elts;
    bool Changed = false;
    for (unsigned i = 0; i < NumElts; ++i) {
      Constant *Elt = Operand->getAggregateElement(i);
      Constant *FlushedElt = FlushFPConstant(Elt, I, IsOutput);
      if (!FlushedElt)
        return nullptr;
      if (FlushedElt != Elt)
        Changed = true;
      Elts.push_back(FlushedElt);
    }

    if (!Changed)
      return Operand;
    return ConstantVector::get(Elts);
  }

  ConstantFP *CFP = dyn_cast<ConstantFP>(Operand);
  if (!CFP)
    return Operand;

  const APFloat &APF = CFP->getValueAPF();
  // TODO: Should this canonicalize nans?
  if (!APF.isDenormal())
    return Operand;

  Type *Ty = CFP->getType();
  DenormalMode DenormMode =
      I->getFunction()->getDenormalMode(Ty->getFltSemantics());
  DenormalMode::DenormalModeKind Mode =
      IsOutput ? DenormMode.Output : DenormMode.Input;
  switch (Mode) {
  default:
    llvm_unreachable("unknown denormal mode");
  case DenormalMode::Dynamic:
    return nullptr;
  case DenormalMode::IEEE:
    return Operand;
  case DenormalMode::PreserveSign:
